        "description": "Transform on non-existent table",
        "operations": [
            {
                "type": "transform_data",
                "table": "nonexistent",
                "transformations": [
                    {
                        "column": "id",
                        "expression": "1"
                    }
                ]
            }
        ]
    }

    with open('migration_error_1.json', 'w') as f:
        json.dump(migration, f, indent=2)

